TriggerOraclev10g.body:
DECLARE envbq_status number; valor_envbq_update number; vro_error tkr_errores%ROWTYPE; BEGIN -- En el caso de INSERT IF INSERTING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_ACTAS_MEDICAS WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_ACTAS_MEDICAS WHERE ID = :NEW.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_ACTAS_MEDICAS ( ENVIO_BQ, ID, ID_USUARIO, FECHA_ACTA_MEDICA, NIVEL_RIESGO, ANALISIS_PLAN, OBSERVACIONES, ID_USUARIO_ACTA, ID_USUARIO_MODIFICA, FECHA_MODIFICACION, ENTRADA_CLOB ) VALUES ( 0, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_USUARIO, :NEW.FECHA_ACTA_MEDICA, :NEW.NIVEL_RIESGO, :NEW.ANALISIS_PLAN, :NEW.OBSERVACIONES, :NEW.ID_USUARIO_ACTA, :NEW.ID_USUARIO_MODIFICA, :NEW.FECHA_MODIFICACION, :NEW.ENTRADA_CLOB ); END IF;
-- En el caso de UPDATE IF UPDATING THEN SELECT (SELECT ENVIO_BQ FROM TKRBQ_ACTAS_MEDICAS WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NULL THEN
INSERT INTO TKRBQ_ACTAS_MEDICAS ( ENVIO_BQ, ID, ID_USUARIO, FECHA_ACTA_MEDICA, NIVEL_RIESGO, ANALISIS_PLAN, OBSERVACIONES, ID_USUARIO_ACTA, ID_USUARIO_MODIFICA, FECHA_MODIFICACION, ENTRADA_CLOB ) VALUES ( 2, -- ENVIO_BQ por defecto :NEW.ID, :NEW.ID_USUARIO, :NEW.FECHA_ACTA_MEDICA, :NEW.NIVEL_RIESGO, :NEW.ANALISIS_PLAN, :NEW.OBSERVACIONES, :NEW.ID_USUARIO_ACTA, :NEW.ID_USUARIO_MODIFICA, :NEW.FECHA_MODIFICACION, :NEW.ENTRADA_CLOB );
ELSE IF envbq_status = 0 THEN valor_envbq_update := 0; ELSE valor_envbq_update := 2; END IF;
UPDATE TKRBQ_ACTAS_MEDICAS SET ENVIO_BQ = valor_envbq_update, ID = :NEW.ID, ID_USUARIO = :NEW.ID_USUARIO, FECHA_ACTA_MEDICA = :NEW.FECHA_ACTA_MEDICA, NIVEL_RIESGO = :NEW.NIVEL_RIESGO, ANALISIS_PLAN = :NEW.ANALISIS_PLAN, OBSERVACIONES = :NEW.OBSERVACIONES, ID_USUARIO_ACTA = :NEW.ID_USUARIO_ACTA, ID_USUARIO_MODIFICA = :NEW.ID_USUARIO_MODIFICA, FECHA_MODIFICACION = :NEW.FECHA_MODIFICACION, ENTRADA_CLOB = :NEW.ENTRADA_CLOB WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF; END IF;
-- Caso DELETE IF DELETING THEN
SELECT (SELECT ENVIO_BQ FROM TKRBQ_ACTAS_MEDICAS WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;
IF envbq_status IS NOT NULL THEN DELETE TKRBQ_ACTAS_MEDICAS WHERE ID = :OLD.ID AND ENVIO_BQ != 1; END IF;
INSERT INTO TKRBQ_ACTAS_MEDICAS ( ENVIO_BQ, ID, ID_USUARIO, FECHA_ACTA_MEDICA, NIVEL_RIESGO, ANALISIS_PLAN, OBSERVACIONES, ID_USUARIO_ACTA, ID_USUARIO_MODIFICA, FECHA_MODIFICACION, ENTRADA_CLOB ) VALUES ( -1, -- ENVIO_BQ para DELETE :OLD.ID, :OLD.ID_USUARIO, :OLD.FECHA_ACTA_MEDICA, :OLD.NIVEL_RIESGO, :OLD.ANALISIS_PLAN, :OLD.OBSERVACIONES, :OLD.ID_USUARIO_ACTA, :OLD.ID_USUARIO_MODIFICA, :OLD.FECHA_MODIFICACION, :OLD.ENTRADA_CLOB ); END IF;
EXCEPTION WHEN OTHERS THEN vro_error.nombre_programa := 'TRG_SYNC_TKR_ACTAS_MEDICAS'; vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ'; vro_error.parametros := 'id de consultas: '||:old.id; uti_ge_excepciones_pkg.p_grabar_log (vro_error);
END;
